# 芒聰聙芒聰聙 Corpus assembly: stripped_70b 芒聤聲 optional kowiki mix 芒聰聙芒聰聙
text_main = Path(args.corpus).read_text(errors='ignore')
text = text_main
kowiki_note = ''
if args.kowiki and os.path.isfile(args.kowiki):
    # Byte-budget kowiki insertion: target_bytes = main_bytes * mix_pct / (100 - mix_pct)
    main_bytes = len(text_main.encode('utf-8'))
    target_kowiki_bytes = max(1, main_bytes * args.kowiki_mix_pct // (100 - args.kowiki_mix_pct))
    chunks = []
    got = 0
    with open(args.kowiki, 'r', encoding='utf-8', errors='ignore') as kf:
        for line in kf:
            try:
                rec = json.loads(line)
                t = rec.get('text', '')
                if not t: continue
                chunks.append(t)
                got += len(t.encode('utf-8'))
                if got >= target_kowiki_bytes: break
            except Exception:
                continue
    kowiki_text = '\n\n'.join(chunks)
    text = text_main + '\n\n' + kowiki_text
    kowiki_note = ' +kowiki(' + str(got) + 'B, ' + str(len(chunks)) + ' docs)'
else:
    print('[r10c WARN] kowiki unavailable 芒聙聰 using stripped_70b only (E7 corpus-diversity recommendation skipped)', flush=True)
print('[r10c] corpus bytes=' + str(len(text.encode('utf-8'))) + kowiki_note, flush=True)

ids = tok(text, add_special_tokens=False)['input_ids']
