# 芒聰聙芒聰聙 DEST1 phi-hook: write 16D phi_vec.json next to each ckpt 芒聰聙芒聰聙
# Schema matches training/alm_phi_vec_logger.hexa canonical layout. Inline
# surrogates: phi_holo_proxy = -log(max(ce, 1e-6)) (positive when ce<1);
# phi_complexity / phi_gwt computed offline by phi_eval_hook_spec. Other
# 13 dims NaN sentinels filled by downstream probes. Sufficient for the
# DEST1 gate ('phi > 1000 evidence') since phi_holo scale reaches 10^4 on
# r9 (12000) and r4 (9051). eval_phi_corr consumes N>=5 save_every=400.
def write_phi_vec(step, save_dir, ce_proxy):
    if not args.phi_hook: return
    import math
    nan = float('nan')
    phi_holo_proxy = -math.log(max(ce_proxy, 1e-6))
    # DEST1 explicit scale: phi_holo in r9/r4 raw is ~10^4. The proxy is
    # unitless and centered near 0 at ce=1. We expose BOTH 芒聙聰 downstream
    # can pick whichever matches the phi_corr_history convention.
    phi_holo_scaled = phi_holo_proxy * 10000.0
    phi_vec = [phi_holo_proxy, nan, nan, nan, nan, nan, nan, nan,
               nan, nan, nan, nan, nan, nan, nan, nan]
    phi_path = os.path.join(save_dir, 'phi_vec.json')
    with open(phi_path, 'w') as f:
        json.dump({'step': step, 'phi_vec': phi_vec,
                   'phi_holo_proxy': phi_holo_proxy,
                   'phi_holo_scaled': phi_holo_scaled,
                   'ce_proxy': ce_proxy,
                   'schema': 'alm_phi_vec_logger_v1',
                   'round': 'r10c',
                   'seed': args.seed,
                   'dest1_gate_scale': 'phi_holo_scaled > 1000'},
                  f, allow_nan=True)
    print('[phi16] step=' + str(step) + ' phi_holo_proxy=' + str(round(phi_holo_proxy,4)) +
          ' phi_holo_scaled=' + str(round(phi_holo_scaled,2)), flush=True)

# 芒聰聙芒聰聙 E7-OSS-01: sentinel via subprocess (authoritative exit code) 芒聰聙芒聰聙
SENTINEL_PROMPTS = ['矛聲聢毛聟聲铆聲聵矛聞赂矛職聰', '矛聵陇毛聤聵 毛聜聽矛聰篓', '铆聲聹锚碌颅矛聳麓 毛陋篓毛聧赂', '毛聰楼毛聼卢毛聥聺矛聺麓毛聻聙', '矛聲聢毛聟聲']
def run_kr_gen(step, reason='cadence'):
    gc.collect(); torch.cuda.empty_cache(); model.eval()
    samples = []
    try:
        for prompt in SENTINEL_PROMPTS:
            iid = tok(prompt, return_tensors='pt').input_ids.to(device)
            with torch.no_grad():
                # Manual greedy loop bypasses unsloth fast_generate kwarg bleed (E7-OSS-04)
                g_seq = iid
                eos_pad = (tok.eos_token_id, tok.pad_token_id)
                for _gs in range(32):
                    logits = model(input_ids=g_seq).logits
                    next_tok = logits[:, -1, :].argmax(dim=-1, keepdim=True)
                    g_seq = torch.cat([g_seq, next_tok], dim=-1)
                    if int(next_tok.item()) in eos_pad:
                        break
                g = g_seq
            gen = tok.decode(g[0][iid.shape[1]:], skip_special_tokens=True)
            samples.append({'prompt': prompt, 'gen': gen[:200]})
            del iid, g
    finally:
        model.train(); gc.collect(); torch.cuda.empty_cache()
    log_path = os.path.join(args.ckpt_dir, 'kr_gen_step_' + str(step) + '.json')
    with open(log_path, 'w') as f:
        json.dump({'step': step, 'reason': reason, 'samples': samples},
                  f, ensure_ascii=False, indent=2)

    # E7-OSS-01: subprocess call; exit 2 = COLLAPSED authoritative
    verdict = 'UNKNOWN'; rc = -1; raw = ''
    try:
        r = subprocess.run([args.hexa_bin, args.sentinel_hexa, log_path],
                           capture_output=True, text=True, timeout=60)
        rc = r.returncode
        raw = (r.stdout or '') + (r.stderr or '')
        if rc == 0: verdict = 'CLEAN'
        elif rc == 2: verdict = 'COLLAPSED'
        else: verdict = 'SENTINEL_ERROR(' + str(rc) + ')'
    except Exception as e:
        # Hexa binary unavailable 芒聙聰 fall back to inline byte-level check
        # (byte-run>=10 ANY byte 芒聙聰 matches kr_gen_sentinel.hexa max_byte_run)
        print('[sentinel FALLBACK] hexa unavailable: ' + str(e), flush=True)
        import collections
        flagged = 0
        for s in (x['gen'] for x in samples):
            by = s.encode('utf-8', errors='ignore')
            run = best = 1
            for j in range(1, len(by)):
                if by[j] == by[j-1]:
                    run += 1
                    if run > best: best = run
                else: run = 1
            if best >= 10: flagged += 1
        verdict = 'COLLAPSED' if flagged >= 3 else 'CLEAN'
        rc = 2 if verdict == 'COLLAPSED' else 0
    print('[sentinel] step=' + str(step) + ' reason=' + reason +
          ' verdict=' + verdict + ' rc=' + str(rc), flush=True)
    if verdict == 'COLLAPSED':
        with open(ABORT_STATUS, 'w') as f:
            f.write('MODE_COLLAPSE_STEP=' + str(step) + '_REASON=' + reason + '\n')
        wstatus('ABORT_MODE_COLLAPSE')
        print('[r10c ABORT] sentinel COLLAPSED at step=' + str(step), flush=True)
        sys.exit(2)

# 芒聰聙芒聰聙 Training loop 芒聰聙芒聰聙
wstatus('TRAINING')
step = 0; t0 = time.time(); best_loss = 1e9
while step < args.steps:
    for batch in dl:
        if step >= args.steps: break
        out = model(input_ids=batch['input_ids'].to(device),
                    labels=batch['labels'].to(device),
                    attention_mask=batch['attention_mask'].to(device))
        loss = out.loss
        loss.backward()
        if (step + 1) % args.grad_accum == 0:
            opt.step(); opt.zero_grad(set_to_none=True)
        step += 1
        lv = float(loss.detach().item())
        if step == 1 or step % 25 == 0:
            elapsed = time.time() - t0
            toks_s = (step * args.batch * args.seq) / max(elapsed, 1e-6)
            print('[step=' + str(step) + '] loss=' + str(round(lv,4)) +
                  ' lr=' + str(args.lr) + ' toks/s=' + str(round(toks_s,0)), flush=True)
        if step == 1 and lv > 8.0:
            with open(ABORT_STATUS, 'w') as f: f.write('STEP1_LOSS=' + str(lv) + '\n')
            wstatus('ABORT_STEP1')
            print('[r10c ABORT] step=1 loss=' + str(lv) + ' > 8.0', flush=True)
            sys.exit(2)
        if lv < best_loss: best_loss = lv

        # E7-OSS-03: sub-threshold loss at early step forces sentinel
        if step <= args.early_step_limit and lv < args.early_loss_gate:
            print('[r10c] early-gate fired: step=' + str(step) + ' loss=' +
                  str(round(lv,4)) + ' < ' + str(args.early_loss_gate) + ' 芒聙聰 force sentinel', flush=True)
            run_kr_gen(step, reason='early_loss_gate')

        if step % args.eval_every == 0:
            run_kr_gen(step, reason='cadence')
        if step % args.save_every == 0:
            save_dir = os.path.join(args.ckpt_dir, 'step_' + str(step))
            model.save_pretrained(save_dir)
            tok.save_pretrained(save_dir)
            meta = {'step': step, 'loss': lv, 'best_loss': best_loss,
                    'lr': args.lr, 'b1': False, 'base': args.base_dir,
                    'warm_start_from': args.adapter_dir, 'round': 'r10c',
                    'seed': args.seed, 'kowiki_mix_pct': args.kowiki_mix_pct,
                    'phi_hook': bool(args.phi_hook),
                    'sentinel_hexa': args.sentinel_hexa,
                    'ossified_rules': ['E7-OSS-01','E7-OSS-02','E7-OSS-03']}
            with open(os.path.join(save_dir, 'train_meta.json'), 'w') as f:
                json.dump(meta, f, indent=2)
            write_phi_vec(step, save_dir, lv)
            print('[save] step=' + str(step) + ' 芒聠聮 ' + save_dir, flush=True)

wstatus('DONE')
print('[r10c] DONE step=' + str(step) + ' best_loss=' + str(round(best_loss,4)), flush=True)
